{"code":"import json
import pandas as pd

business_info = locals()['var_function-call-4621153359484241976']

category_reviews = {}

for business in business_info:
    description = business.get('description', '')
    review_count = int(business.get('review_count', 0))

    # Extract categories from the description
    if 'seeking' in description:
        categories_str = description.split('seeking', 1)[1].strip()
        # Remove trailing period if exists and split by comma
        categories_list = [cat.strip() for cat in categories_str.replace('.', '').split(',')]

        for category in categories_list:
            if category:
                category_reviews[category] = category_reviews.get(category, 0) + review_count
    elif 'category of' in description:
        categories_str = description.split('category of', 1)[1].strip()
        categories_list = [cat.strip() for cat in categories_str.replace('.', '').replace('\','').split(',')]
        for category in categories_list:
            if category:
                category_reviews[category] = category_reviews.get(category, 0) + review_count

# Sort categories by total reviews and get the top 5
sorted_categories = sorted(category_reviews.items(), key=lambda item: item[1], reverse=True)
top_5_categories = sorted_categories[:5]

print("__RESULT__:")
print(json.dumps(top_5_categories))
"}

